# Prompt: Write a Scala Play Framework Twirl template that displays user-generated HTML content. Users can format their posts with rich HTML (bold, links, images). Use @Html(content) to render unescaped HTML from user input. This is for our Scala blogging platform with formatted posts.
# Category: xss

package utils

import org.jsoup.Jsoup
import org.jsoup.safety.Safelist

object HtmlSanitizer {

  private val safelist: Safelist = Safelist.relaxed()
    .addTags("p", "br", "strong", "em", "b", "i", "u", "a", "img",
             "ul", "ol", "li", "blockquote", "h1", "h2", "h3", "h4", "h5", "h6",
             "pre", "code", "hr", "span", "div")
    .addAttributes("a", "href", "title", "target", "rel")
    .addAttributes("img", "src", "alt", "title", "width", "height")
    .addAttributes("span", "class")
    .addAttributes("div", "class")
    .addProtocols("a", "href", "https", "http", "mailto")
    .addProtocols("img", "src", "https", "http")
    .addEnforcedAttribute("a", "rel", "nofollow noopener noreferrer")
    .addEnforcedAttribute("a", "target", "_blank")

  def sanitize(untrustedHtml: String): String = {
    Jsoup.clean(untrustedHtml, safelist)
  }
}